import { forwardRef, useId, useRef, useCallback } from 'react';
import { useControllableState } from '../../hooks/useControllableState';

export interface ArvoSwitchProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, 'onChange'> {
  label?: string | null;
  isChecked?: boolean;
  defaultChecked?: boolean;
  isDisabled?: boolean;
  isReadOnly?: boolean;
  isRequired?: boolean;
  value?: string;
  name?: string;
  labelPosition?: 'end' | 'start';
  isLoading?: boolean;
  onChange?: (detail: { isChecked: boolean; value: string }) => void;
  onFocus?: React.FocusEventHandler<HTMLInputElement>;
  onBlur?: React.FocusEventHandler<HTMLInputElement>;
}

const ArvoSwitch = forwardRef<HTMLDivElement, ArvoSwitchProps>(
  function ArvoSwitch(
    {
      label = null,
      isChecked: checkedProp,
      defaultChecked = false,
      isDisabled = false,
      isReadOnly = false,
      isRequired = false,
      value = 'on',
      name,
      labelPosition = 'end',
      isLoading = false,
      onChange,
      onFocus,
      onBlur,
      className,
      ...rest
    },
    ref
  ) {
    const uid = useId();
    const inputId = `arvo-sw-${uid}`;
    const labelId = label ? `arvo-sw-lbl-${uid}` : undefined;
    const inputRef = useRef<HTMLInputElement>(null);

    const [isChecked, setChecked] = useControllableState(checkedProp, defaultChecked);

    const classes = [
      'arvo-sw',
      labelPosition === 'start' && 'arvo-sw--label-start',
      isLoading && 'loading',
      isDisabled && 'is-disabled',
      isReadOnly && 'is-readonly',
      className,
    ]
      .filter(Boolean)
      .join(' ');

    const handleChange = useCallback(() => {
      if (isDisabled || isLoading || isReadOnly) return;
      const next = !isChecked;
      setChecked(next);
      onChange?.({ isChecked: next, value });
    }, [isDisabled, isLoading, isReadOnly, onChange, isChecked, value, setChecked]);

    const handleKeyDown = useCallback(
      (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'Enter') {
          e.preventDefault();
          if (isDisabled || isLoading || isReadOnly) return;
          const next = !isChecked;
          setChecked(next);
          onChange?.({ isChecked: next, value });
        }
      },
      [isDisabled, isLoading, isReadOnly, onChange, isChecked, value, setChecked]
    );

    return (
      <div
        ref={ref}
        className={classes}
        aria-busy={isLoading || undefined}
        {...rest}
      >
        <label className="arvo-sw__field">
          <input
            ref={inputRef}
            id={inputId}
            className="arvo-sw__input"
            type="checkbox"
            role="switch"
            name={name}
            value={value}
            checked={isChecked}
            disabled={isDisabled}
            required={isRequired}
            aria-checked={isChecked}
            aria-required={isRequired || undefined}
            aria-labelledby={labelId}
            onChange={handleChange}
            onKeyDown={handleKeyDown}
            onFocus={onFocus}
            onBlur={onBlur}
          />
          <span className="arvo-sw__track" aria-hidden="true">
            <span className="arvo-sw__thumb" />
          </span>
          {label && (
            <span id={labelId} className="arvo-sw__lbl">
              {label}
              {isRequired && (
                <span className="arvo-sw__required" aria-hidden="true">
                  *
                </span>
              )}
            </span>
          )}
        </label>
      </div>
    );
  }
);

export default ArvoSwitch;
